class TabConfig {
  final String title;
  final IconData icon;

  // Para formulário
  final List<FieldConfig>? fields;

  // Para grid
  final bool isGrid;
  final String? endpoint;   // API endpoint
  final String? parentField; // Nome do campo pai no backend

  TabConfig({
    required this.title,
    required this.icon,
    this.fields,
    this.isGrid = false,
    this.endpoint,
    this.parentField,
  });
}
